const trigger = $('Workflow Trigger').first().json;
const leadDb  = $input.first().json || {};

const leadData = {
  Nome       : leadDb.Nome       || leadDb.nome       || null,
  Email      : leadDb.Email      || leadDb.email      || null,
  CPF        : leadDb.CPF        || leadDb.cpf        || null,
  Telefone   : leadDb.Telefone   || trigger.chatid,
  QtdPessoas : leadDb.QtdPessoas || leadDb.qtd_pessoas || null,
  Navio      : leadDb.Navio      || leadDb.navio       || null,
  Estilo     : leadDb.Estilo     || leadDb.estilo      || null,
  Orcamento  : leadDb.Orcamento  || leadDb.orcamento   || null,
  Pontuacao  : parseInt(leadDb.Pontuacao || leadDb.pontuacao || 0),
  Status     : leadDb.Status     || leadDb.status       || 'BAIXA',
  Etapa      : leadDb.Etapa      || leadDb.etapa       || 'negociacao',
  ja_fez_cruzeiro   : leadDb.ja_fez_cruzeiro   !== undefined ? leadDb.ja_fez_cruzeiro   : null,
  valores_enviados  : leadDb.valores_enviados   || false,
  tentativas_valor  : parseInt(leadDb.tentativas_valor || 0),
  em_qual_etapa     : leadDb.em_qual_etapa || 'e1'
};

const context = {
  chatid          : trigger.chatid,
  mensagem        : trigger.mensagem,
  urlchatwoot     : trigger.urlchatwoot,
  account_id      : trigger.account_id,
  conversation_id : trigger.conversation_id,
  chatwoottoken   : trigger.chatwoottoken,
  contact_id      : trigger.contact_id,
  lead_data       : leadData
};

return [{ json: { context, leadData, trigger } }];

const trigger      = $('Workflow Trigger').first().json;
const promptResult = $('Call WF_MontarPrompt1').first().json;
const kbResult     = $input.first().json;

const kbContext = kbResult.textoFormatado || '';
const systemMessage = promptResult.systemMessage
  + (kbContext
      ? '\n\n# CONTEXTO DA BASE DE CONHECIMENTO (use estas informações para responder)\n' + kbContext
      : '');

return [{ json: {
  systemMessage,
  userMessage : trigger.mensagem,
  etapa       : promptResult.etapa,
  chatid      : trigger.chatid,
  urlchatwoot : trigger.urlchatwoot,
  account_id  : trigger.account_id,
  conversation_id : trigger.conversation_id,
  chatwoottoken   : trigger.chatwoottoken,
  contact_id      : trigger.contact_id
} }];

const trigger   = $('Workflow Trigger').first().json;
let rawText = ($input.first().json.output || $input.first().json.text || '');

let parsed = {};
try {
  const cleaned = rawText
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    resposta: rawText,
    acoes: {
      salvar_lead       : null,
      enviar_video      : false,
      pausar_atendimento: false,
      handoff           : false,
      resumo_handoff    : null
    }
  };
}

const acoes   = parsed.acoes || {};
const resposta = parsed.resposta || rawText;

return [{
  json: {
    resposta,
    acoes_salvar_lead       : acoes.salvar_lead        || null,
    acoes_enviar_video      : acoes.enviar_video       === true,
    acoes_pausar            : acoes.pausar_atendimento === true,
    acoes_handoff           : acoes.handoff            === true,
    acoes_resumo_handoff    : acoes.resumo_handoff     || null,
    chatid                  : trigger.chatid,
    urlchatwoot             : trigger.urlchatwoot,
    account_id              : trigger.account_id,
    conversation_id         : trigger.conversation_id,
    chatwoottoken           : trigger.chatwoottoken,
    contact_id              : trigger.contact_id,
    enviar_materiais        : acoes.enviar_materiais || false

  }
}];

const trigger  = $('Workflow Trigger').first().json;
const leadData = $('Prepare Context').first().json.leadData || {};
const mensagem = (trigger.mensagem || '').toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const kwCruzeiros = [
  'navio','artista','show','musica','camarote','experience resource','suite','varanda','interior',
  'preco','valor','quanto','custa','parcela','entrada','sinal','reserva','disponivel',
  'data','quando sai','quando vai','destino','rota','itinerario',
  'noite','dia','duracao','cancun','miami','bahamas','caribe','mediterran',
  'oceanview','balcao','janela'
];

const kwConhecimento = [
  'inclui','incluso','inclusa','o que tem','o que esta','o que vem',
  'bebida','alcool','refrigerante','suco','alimentacao','refeicao','cafe','almoco','jantar',
  'boleto','pix','cartao','credito','debito','forma de pagamento','parcelamento','como pago',
  'como funciona','processo','como faz','documento','rg','passaporte','cpf',
  'crianca','menor','idoso','acessibilidade',
  'transfer','onibus','chegada','check-in','check-out','porto','santos',
  'seguro','cancelamento','devolucao','reembolso','politica',
  'wifi','internet','spa','academia','piscina','restaurante',
  'contato','telefone','whatsapp','email','simone','consultora','falar com',
  'duvida','pergunta','informacao','mais detalhes'
];

let ptsCruzeiros = 0;
let ptsConhecimento = 0;

for (const kw of kwCruzeiros)    { if (mensagem.includes(kw)) ptsCruzeiros++; }
for (const kw of kwConhecimento) { if (mensagem.includes(kw)) ptsConhecimento++; }

// Se lead já tem navio definido e mensagem tem keyword de cruzeiro → peso extra
if (leadData.Navio && ptsCruzeiros > 0) ptsCruzeiros += 2;

// Empate → no contexto de pagamento prioriza 'conhecimento' (FAQ de pagamento)
const tipo_kb = ptsCruzeiros > ptsConhecimento ? 'cruzeiros' : 'conhecimento';

// Propagar tudo que veio do Call WF_MontarPrompt + o tipo decidido
const promptData = $('Call WF_MontarPrompt1').first().json;

return [{
  json: {
    ...promptData,
    tipo_kb,
    _classify_debug: { ptsCruzeiros, ptsConhecimento, decisao: tipo_kb }
  }
}];
